// Services
@org.springframework.stereotype.Service
public class ProductService {

    private static final Logger log = LoggerFactory.getLogger(ProductService.class);
    private static final String PRODUCT_INDEX = "products";
    private static final String SEARCH_QUERY_INDEX = "search_queries";

    private final RestHighLevelClient esClient;
    private final ObjectMapper objectMapper; // For converting Product to JSON
    private final SearchQueryService searchQueryService;

    public ProductService(RestHighLevelClient esClient, SearchQueryService searchQueryService) {
        this.esClient = esClient;
        this.objectMapper = new ObjectMapper();
        this.searchQueryService = searchQueryService;
    }

    public String indexProduct(Product product) throws IOException {
        if (product.getId() == null) {
            product.setId(UUID.randomUUID().toString());
        }
        IndexRequest request = new IndexRequest(PRODUCT_INDEX)
                .id(product.getId())
                .source(objectMapper.writeValueAsString(product), org.elasticsearch.common.xcontent.XContentType.JSON);

        IndexResponse response = esClient.index(request, RequestOptions.DEFAULT);
        log.info("Indexed product with ID: {}", response.getId());
        return response.getId();
    }

    public Product getProductById(String id) throws IOException {
        GetRequest request = new GetRequest(PRODUCT_INDEX, id);
        GetResponse response = esClient.get(request, RequestOptions.DEFAULT);

        if (response.isExists()) {
            return objectMapper.readValue(response.getSourceAsString(), Product.class);
        }
        return null;
    }

    public boolean deleteProduct(String id) throws IOException {
        DeleteRequest request = new DeleteRequest(PRODUCT_INDEX, id);
        DeleteResponse response = esClient.delete(request, RequestOptions.DEFAULT);
        return response.getResult() == org.elasticsearch.action.delete.DeleteResponse.Result.DELETED;
    }

    public SearchResult searchProducts(String query, List<String> categories, List<String> brands, Double minPrice, Double maxPrice, int page, int size) throws IOException {
        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX);
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();

        // Pagination
        int from = page * size;
        searchSourceBuilder.from(from);
        searchSourceBuilder.size(size);
        searchSourceBuilder.timeout(new TimeValue(60, TimeUnit.SECONDS));

        // Build the main query
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (query != null && !query.trim().isEmpty()) {
            // Full-text search across name and description
            boolQuery.must(QueryBuilders.multiMatchQuery(query, "name^3", "description^1")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness("AUTO")); // Add fuzziness for better recall
            
            // Log the search query
            searchQueryService.logSearchQuery(query);
        } else {
            // If no specific query, match all to show all products or apply filters
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        // Filters (faceted navigation)
        if (categories != null && !categories.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category.keyword", categories));
        }
        if (brands != null && !brands.isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", brands));
        }
        if (minPrice != null || maxPrice != null) {
            RangeQueryBuilder priceRangeQuery = QueryBuilders.rangeQuery("price");
            if (minPrice != null) {
                priceRangeQuery.gte(minPrice);
            }
            if (maxPrice != null) {
                priceRangeQuery.lte(maxPrice);
            }
            boolQuery.filter(priceRangeQuery);
        }

        searchSourceBuilder.query(boolQuery);

        // Aggregations for facets
        // Category Facet
        TermsAggregationBuilder categoryAgg = AggregationBuilders.terms("category_facet")
                .field("category.keyword")
                .size(10) // Top 10 categories
                .order(BucketOrder.count(false)); // Sort by count descending
        searchSourceBuilder.aggregation(categoryAgg);

        // Brand Facet
        TermsAggregationBuilder brandAgg = AggregationBuilders.terms("brand_facet")
                .field("brand.keyword")
                .size(10) // Top 10 brands
                .order(BucketOrder.count(false));
        searchSourceBuilder.aggregation(brandAgg);

        // Price Range Facet
        RangeAggregationBuilder priceAgg = AggregationBuilders.range("price_facet")
                .field("price")
                .addRange(0.0, 50.0)
                .addRange(50.0, 100.0)
                .addRange(100.0, 200.0)
                .addUnboundedFrom(200.0, "200+"); // Custom label for ranges
        searchSourceBuilder.aggregation(priceAgg);

        // Sort by relevance (default) or a specific field if desired
        // searchSourceBuilder.sort(new FieldSortBuilder("price").order(SortOrder.ASC));

        searchRequest.source(searchSourceBuilder);

        log.debug("Elasticsearch Search Request: {}", searchSourceBuilder.toString());

        SearchResponse searchResponse = esClient.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = new ArrayList<>();
        for (SearchHit hit : searchResponse.getHits().getHits()) {
            Product product = objectMapper.readValue(hit.getSourceAsString(), Product.class);
            product.setId(hit.getId()); // Ensure product ID is set from Elasticsearch _id
            products.add(product);
        }

        List<Facet> facets = new ArrayList<>();
        Aggregations aggregations = searchResponse.getAggregations();

        if (aggregations != null) {
            // Process Category Facet
            Terms categoryTerms = aggregations.get("category_facet");
            if (categoryTerms != null) {
                List<FacetValue> categoryValues = categoryTerms.getBuckets().stream()
                        .map(bucket -> new FacetValue(bucket.getKeyAsString(), bucket.getDocCount()))
                        .collect(Collectors.toList());
                facets.add(new Facet("category", categoryValues));
            }

            // Process Brand Facet
            Terms brandTerms = aggregations.get("brand_facet");
            if (brandTerms != null) {
                List<FacetValue> brandValues = brandTerms.getBuckets().stream()
                        .map(bucket -> new FacetValue(bucket.getKeyAsString(), bucket.getDocCount()))
                        .collect(Collectors.toList());
                facets.add(new Facet("brand", brandValues));
            }

            // Process Price Range Facet
            Range priceRange = aggregations.get("price_facet");
            if (priceRange != null) {
                List<FacetValue> priceValues = priceRange.getBuckets().stream()
                        .map(bucket -> new FacetValue(bucket.getKeyAsString(), bucket.getDocCount()))
                        .collect(Collectors.toList());
                facets.add(new Facet("price_range", priceValues));
            }
        }

        return new SearchResult(products, searchResponse.getHits().getTotalHits().value, facets);
    }
}

@org.springframework.stereotype.Service
public class SearchQueryService {

    private static final Logger log = LoggerFactory.getLogger(SearchQueryService.class);
    private static final String SEARCH_QUERY_INDEX = "search_queries";

    private final RestHighLevelClient esClient;
    private final ObjectMapper objectMapper;

    public SearchQueryService(RestHighLevelClient esClient) {
        this.esClient = esClient;
        this.objectMapper = new ObjectMapper();
    }

    public String logSearchQuery(String queryText) {
        try {
            SearchQuery searchQuery = new SearchQuery(queryText);
            IndexRequest request = new IndexRequest(SEARCH_QUERY_INDEX)
                    .id(searchQuery.getId())
                    .source(objectMapper.writeValueAsString(searchQuery), org.elasticsearch.common.xcontent.XContentType.JSON);

            IndexResponse response = esClient.index(request, RequestOptions.DEFAULT);
            log.debug("Logged search query with ID: {}", response.getId());
            return response.getId();
        } catch (IOException e) {
            log.error("Failed to log search query '{}': {}", queryText, e.getMessage());
            return null;
        }
    }
}

// Controllers
@RestController
@RequestMapping("/api/products")
public class ProductController {

    private static final Logger log = LoggerFactory.getLogger(ProductController.class);

    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
    }

    @PostMapping
    public ResponseEntity<Product> createProduct(@RequestBody Product product) {
        try {
            String id = productService.indexProduct(product);
            product.setId(id);
            return new ResponseEntity<>(product, HttpStatus.CREATED);
        } catch (IOException e) {
            log.error("Error creating product: {}", e.getMessage(), e);
            return new ResponseEntity<>(HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) {
        try {
            Product product = productService.getProductById(id);
            if (product != null) {
                return new ResponseEntity<>(product, HttpStatus.OK);
            }
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        } catch (IOException e) {
            log.error("Error retrieving product by ID {}: {}", id, e.getMessage(), e);
            return new ResponseEntity<>(HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteProduct(@PathVariable String id) {
        try {
            if (productService.deleteProduct(id)) {
                return new ResponseEntity<>(HttpStatus.NO_CONTENT);
            }
            return new ResponseEntity<>(HttpStatus.NOT_FOUND);
        } catch (IOException e) {
            log.error("Error deleting product by ID {}: {}", id, e.getMessage(), e);
            return new ResponseEntity<>(HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }

    @GetMapping("/search")
    public ResponseEntity<SearchResult> searchProducts(
            @RequestParam(required = false) String q,
            @RequestParam(required = false) List<String> category,
            @RequestParam(required = false) List<String> brand,
            @RequestParam(required = false) Double minPrice,
            @RequestParam(required = false) Double maxPrice,
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "10") int size) {
        try {
            SearchResult result = productService.searchProducts(q, category, brand, minPrice, maxPrice, page, size);
            return new ResponseEntity<>(result, HttpStatus.OK);
        } catch (IOException e) {
            log.error("Error searching products: {}", e.getMessage(), e);
            return new ResponseEntity<>(HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }
}

